insert into public.libraries
  (slug, name_en, name_ar, city_en, city_ar, description_en, description_ar, location)
values
  ('ramallah-childrens-library', 'Ramallah Children''s Library', 'مكتبة رام الله للأطفال', 'Ramallah', 'رام الله', 'A sunny neighbourhood library known for its lively storytelling corner.', 'مكتبة حيّ مشمسة تشتهر بزاوية حكايا نابضة بالحياة.', extensions.st_setsrid(extensions.st_makepoint(35.2058, 31.9026), 4326)::extensions.geography),
  ('al-bireh-hilltop-library', 'Hilltop Library', 'مكتبة رأس التلة', 'Al-Bireh', 'البيرة', 'A quiet reading room overlooking the hills, popular with young writers.', 'قاعة قراءة هادئة تطلّ على التلال، يحبّها الكتّاب الصغار.', extensions.st_setsrid(extensions.st_makepoint(35.2168, 31.9127), 4326)::extensions.geography),
  ('nablus-old-city-reading-house', 'Old City Reading House', 'بيت القراءة في البلدة القديمة', 'Nablus', 'نابلس', 'Stone arches, floor cushions and shelves of stories in the heart of the old city.', 'أقواس حجرية ووسائد أرضية ورفوف من الحكايات في قلب البلدة القديمة.', extensions.st_setsrid(extensions.st_makepoint(35.2544, 32.2211), 4326)::extensions.geography),
  ('hebron-family-library', 'Hebron Family Library', 'مكتبة الخليل العائلية', 'Hebron', 'الخليل', 'A busy family library where grandparents and children read side by side.', 'مكتبة عائلية نشطة يقرأ فيها الأجداد والأطفال جنبًا إلى جنب.', extensions.st_setsrid(extensions.st_makepoint(35.0998, 31.5326), 4326)::extensions.geography),
  ('bethlehem-star-library', 'Star of Bethlehem Library', 'مكتبة نجمة بيت لحم', 'Bethlehem', 'بيت لحم', 'A small library with a big puppet theatre and a weekly reading club.', 'مكتبة صغيرة فيها مسرح دمى كبير ونادي قراءة أسبوعي.', extensions.st_setsrid(extensions.st_makepoint(35.2024, 31.7054), 4326)::extensions.geography),
  ('jenin-green-hills-library', 'Green Hills Library', 'مكتبة التلال الخضراء', 'Jenin', 'جنين', 'Surrounded by fields, this library runs nature walks that end in stories.', 'تحيط بها الحقول، وتنظّم جولات في الطبيعة تنتهي دائمًا بحكاية.', extensions.st_setsrid(extensions.st_makepoint(35.2951, 32.4597), 4326)::extensions.geography),
  ('tulkarm-community-library', 'Tulkarm Community Library', 'مكتبة طولكرم المجتمعية', 'Tulkarm', 'طولكرم', 'A community hub where teenagers volunteer to read with younger children.', 'ملتقى مجتمعي يتطوّع فيه اليافعون للقراءة مع الأطفال الأصغر.', extensions.st_setsrid(extensions.st_makepoint(35.0286, 32.3104), 4326)::extensions.geography),
  ('gaza-sea-breeze-library', 'Sea Breeze Library', 'مكتبة نسيم البحر', 'Gaza', 'غزة', 'Steps from the shore, with a whole shelf devoted to stories about the sea.', 'على بُعد خطوات من الشاطئ، وفيها رفّ كامل لحكايات البحر.', extensions.st_setsrid(extensions.st_makepoint(34.456, 31.5069), 4326)::extensions.geography),
  ('khan-younis-oasis-library', 'Reading Oasis Library', 'مكتبة واحة القراءة', 'Khan Younis', 'خان يونس', 'A shaded courtyard library famous for its summer reading marathons.', 'مكتبة ذات ساحة ظليلة تشتهر بماراثونات القراءة الصيفية.', extensions.st_setsrid(extensions.st_makepoint(34.3063, 31.3462), 4326)::extensions.geography)
on conflict (slug) do update set
  name_en = excluded.name_en, name_ar = excluded.name_ar,
  city_en = excluded.city_en, city_ar = excluded.city_ar,
  description_en = excluded.description_en, description_ar = excluded.description_ar,
  location = excluded.location;

insert into public.books
  (slug, title_en, title_ar, author_en, author_ar, age_min, age_max, summary_en, summary_ar, cover_emoji, cover_color)
values
  ('the-olive-trees-secret', 'The Olive Tree''s Secret', 'سرّ شجرة الزيتون', 'Layla Haddad', 'ليلى حداد', 6, 9, 'Noor discovers that her grandmother''s stories are hidden among the branches of the oldest olive tree in the grove.', 'تكتشف نور أن حكايات جدّتها مخبأة بين أغصان أقدم شجرة زيتون في الكرم.', '🫒', '#7a8450'),
  ('postcards-from-the-sea', 'Postcards from the Sea', 'بطاقات من البحر', 'Omar Nasser', 'عمر ناصر', 8, 12, 'Karim writes postcards to a pen friend he has never met, describing the sea in a new way each week.', 'يكتب كريم بطاقات بريدية لصديق مراسلة لم يلتقِ به قط، واصفًا البحر بطريقة جديدة كل أسبوع.', '🌊', '#2c6e91'),
  ('the-kite-that-learned-to-read', 'The Kite That Learned to Read', 'الطائرة الورقية التي تعلّمت القراءة', 'Rania Saleh', 'رانية صالح', 5, 8, 'A curious kite peeks through classroom windows until, letter by letter, it learns to read the sky.', 'طائرة ورقية فضولية تسترق النظر من نوافذ الصفوف حتى تتعلّم، حرفًا حرفًا، قراءة السماء.', '🪁', '#c2571f'),
  ('grandmothers-bread', 'Grandmother''s Bread', 'خبز جدّتي', 'Khalil Mansour', 'خليل منصور', 4, 7, 'Every Friday the whole building wakes to the smell of Teta''s taboon bread — and one morning, little Zain gets to help.', 'في كل جمعة تستيقظ العمارة كلّها على رائحة خبز الطابون عند التيتا، وفي صباح ما يحين دور زين الصغير ليساعد.', '🍞', '#a97847'),
  ('the-night-of-falling-stars', 'The Night of Falling Stars', 'ليلة الشهب', 'Huda Awad', 'هدى عوض', 9, 12, 'Three cousins camp on the roof to count shooting stars and end up mapping their own constellation of wishes.', 'يخيّم ثلاثة من أبناء العمومة على السطح لعدّ الشهب، فيرسمون في النهاية كوكبة أمنياتهم الخاصة.', '🌠', '#1f2a5e'),
  ('a-map-of-small-wonders', 'A Map of Small Wonders', 'خريطة العجائب الصغيرة', 'Samir Qasem', 'سمير قاسم', 7, 10, 'Dana draws a map of her street where every tiny thing — a nest, a crack, a cat — is a wonder worth marking.', 'ترسم دانا خريطة لشارعها تكون فيها كل الأشياء الصغيرة — عشّ، شقّ في الجدار، قطة — عجيبةً تستحق التدوين.', '🗺️', '#3e7c59'),
  ('the-cat-of-the-old-souq', 'The Cat of the Old Souq', 'قطة السوق القديم', 'Layla Haddad', 'ليلى حداد', 5, 8, 'A market cat knows every shopkeeper''s mood — and teaches a shy new boy how to read faces before words.', 'قطة السوق تعرف مزاج كل بائع، وتعلّم فتى خجولًا جديدًا كيف يقرأ الوجوه قبل الكلمات.', '🐈', '#b0762a'),
  ('seven-keys-and-a-door', 'Seven Keys and a Door', 'سبعة مفاتيح وباب', 'Majd Barakat', 'مجد بركات', 10, 14, 'An adventure of riddles: seven keys, one locked library door, and a group of friends who refuse to give up.', 'مغامرة ألغاز: سبعة مفاتيح وباب مكتبة مقفل ومجموعة أصدقاء يرفضون الاستسلام.', '🗝️', '#5b4a68'),
  ('the-almond-blossom-parade', 'The Almond Blossom Parade', 'موكب زهر اللوز', 'Rania Saleh', 'رانية صالح', 4, 7, 'When the almond trees bloom, the whole village children march in a parade of petals, drums and giggles.', 'حين يزهر اللوز، يخرج أطفال القرية كلّهم في موكب من البتلات والطبول والضحكات.', '🌸', '#c96d84'),
  ('voices-in-the-valley', 'Voices in the Valley', 'أصوات في الوادي', 'Huda Awad', 'هدى عوض', 11, 15, 'A young radio club records the stories of their valley — and learns that listening is harder, and braver, than speaking.', 'نادي إذاعة فتيّ يسجّل حكايات الوادي، ليتعلّم أعضاؤه أن الإصغاء أصعب من الكلام وأكثر شجاعة.', '🏞️', '#2f6157'),
  ('the-little-librarian', 'The Little Librarian', 'أمينة المكتبة الصغيرة', 'Khalil Mansour', 'خليل منصور', 6, 9, 'Salwa organises the books in her building''s stairwell into a tiny library — and becomes the youngest librarian in town.', 'ترتّب سلوى الكتب على درج عمارتها في مكتبة صغيرة، فتصبح أصغر أمينة مكتبة في البلدة.', '📚', '#8c1820'),
  ('rain-over-the-camp', 'Rain Over the Camp', 'مطر فوق المخيم', 'Omar Nasser', 'عمر ناصر', 9, 13, 'After a rainy week, friends collect runoff water to grow a rooftop garden that surprises the whole neighbourhood.', 'بعد أسبوع ماطر، يجمع الأصدقاء مياه المطر ليزرعوا حديقة سطح تفاجئ الحيّ كلّه.', '🌧️', '#41668c'),
  ('the-turtle-who-carried-stories', 'The Turtle Who Carried Stories', 'السلحفاة حاملة الحكايات', 'Dima Khoury', 'ديمة خوري', 4, 6, 'A slow old turtle carries one story in her shell to each village she visits — and collects a new one before she leaves.', 'سلحفاة عجوز بطيئة تحمل في صدفتها حكاية لكل قرية تزورها، وتجمع حكاية جديدة قبل أن تغادر.', '🐢', '#4e7d3a'),
  ('my-brother-the-inventor', 'My Brother the Inventor', 'أخي المخترع', 'Samir Qasem', 'سمير قاسم', 7, 10, 'Basil turns broken toys and bottle caps into wonderful machines — even if they only work half the time.', 'يحوّل باسل الألعاب المكسورة وأغطية الزجاجات إلى آلات مدهشة، حتى لو لم تعمل إلا نصف الوقت.', '🔧', '#7d5427'),
  ('the-colour-of-zaatar', 'The Colour of Za''atar', 'لون الزعتر', 'Dima Khoury', 'ديمة خوري', 6, 9, 'On a hillside walk with her father, Jana learns the names, smells and colours of every wild herb — and one family secret recipe.', 'في نزهة على سفح التل مع والدها، تتعلّم جنى أسماء الأعشاب البرية وروائحها وألوانها، ووصفة عائلية سرّية واحدة.', '🌿', '#557a3c'),
  ('letters-to-a-lighthouse', 'Letters to a Lighthouse', 'رسائل إلى منارة', 'Majd Barakat', 'مجد بركات', 10, 14, 'Every week Yara leaves a letter for the keeper of an old lighthouse. One stormy day, the answers begin to arrive.', 'تترك يارا كل أسبوع رسالة لحارس منارة قديمة، وفي يوم عاصف تبدأ الردود بالوصول.', '🌅', '#a34b2e'),
  ('the-orchard-detectives', 'The Orchard Detectives', 'محقّقو البستان', 'Rania Saleh', 'رانية صالح', 8, 11, 'Who is eating the apricots at night? Four friends set up a stakeout and follow clues through the orchard.', 'من يأكل المشمش ليلًا؟ أربعة أصدقاء ينصبون كمينًا ويتتبّعون الأدلة عبر البستان.', '🕵️', '#c78f2d'),
  ('a-song-for-the-hoopoe', 'A Song for the Hoopoe', 'أغنية للهدهد', 'Huda Awad', 'هدى عوض', 5, 8, 'A hoopoe stops singing, and the children of the valley try every sound they know to bring its song back.', 'يتوقّف الهدهد عن الغناء، فيجرّب أطفال الوادي كل صوت يعرفونه ليعيدوا إليه أغنيته.', '🐦', '#c2803e'),
  ('the-paper-boat-race', 'The Paper Boat Race', 'سباق القوارب الورقية', 'Khalil Mansour', 'خليل منصور', 6, 9, 'After the rain, the alley becomes a river and every child folds a boat. This year, Lina has a secret design.', 'بعد المطر يصير الزقاق نهرًا ويطوي كل طفل قاربه. هذا العام، لدى لينا تصميم سرّي.', '⛵', '#33718f'),
  ('stars-above-the-rooftops', 'Stars Above the Rooftops', 'نجوم فوق السطوح', 'Majd Barakat', 'مجد بركات', 12, 15, 'A rooftop astronomy club, a borrowed telescope, and a summer that changes how five teenagers see their city — and themselves.', 'نادي فلك على السطح ومقراب مستعار وصيف يغيّر نظرة خمسة يافعين إلى مدينتهم وإلى أنفسهم.', '✨', '#2b2350')
on conflict (slug) do update set
  title_en = excluded.title_en, title_ar = excluded.title_ar,
  author_en = excluded.author_en, author_ar = excluded.author_ar,
  age_min = excluded.age_min, age_max = excluded.age_max,
  summary_en = excluded.summary_en, summary_ar = excluded.summary_ar,
  cover_emoji = excluded.cover_emoji, cover_color = excluded.cover_color;

