  ('the-feelings-mirror', 'The Feelings Mirror', 'مرآة المشاعر', 'empathy', 6, 9, 15, 'the-cat-of-the-old-souq', 'In pairs, children mirror each other''s facial expressions and guess the feeling, then find the same feelings in the story''s characters.', 'يقلّد الأطفال، في ثنائيات، تعابير وجوه بعضهم بعضًا ويخمّنون الشعور، ثم يبحثون عن المشاعر نفسها لدى شخصيات القصة.', 'Naming a feeling out loud is the fastest door into a shy group.', 'تسمية الشعور بصوت عالٍ هي أسرع باب للوصول إلى مجموعة خجولة.', '[0.031043,0.082776,0.009638,-0.003943,-0.069693,0.010565,0.070446,-0.010113,0.008434,-0.048526,0.133281,-0.052618,0.123877,-0.043206,0.063110,0.045204,-0.015899,0.104989,-0.108054,-0.012198,-0.081250,-0.068038,0.088943,-0.037798,-0.013256,0.035232,-0.003792,-0.085350,0.028850,0.051995,0.097114,-0.028308,0.138425,-0.029224,0.014260,0.052421,0.004535,-0.002708,0.022198,0.012177,-0.073510,-0.026819,-0.046841,0.016739,-0.050756,0.006364,-0.075062,-0.041407,-0.017571,-0.029573,-0.073397,-0.067372,-0.042603,-0.020335,-0.072257,0.028437,0.007259,0.002139,-0.046995,0.072051,-0.040949,-0.020964,-0.084515,0.079307,-0.055331,0.036136,0.007233,-0.014307,-0.011806,-0.015824,0.014183,0.057290,-0.019692,-0.024137,-0.005484,0.070722,-0.068568,-0.003521,0.001510,-0.055791,0.026207,-0.056485,0.003279,0.025955,-0.036381,-0.002207,0.067908,-0.021710,-0.087037,0.000552,-0.148368,0.001972,0.027706,0.056582,-0.009022,-0.039842,-0.054107,0.027203,0.023375,0.081094,0.024459,0.052568,0.000653,0.074529,0.013605,0.042744,0.040317,-0.051613,0.042768,-0.054964,-0.106867,-0.037566,-0.000528,0.034489,-0.014221,-0.013728,0.111153,0.007526,0.025462,0.024334,-0.001641,-0.000320,-0.056057,-0.052766,0.080761,-0.137233,0.007359,0.017534,0.065109,-0.012368,0.052135,0.003421,0.008700,0.034919,-0.032923,-0.068463,0.035461,0.097071,-0.072471,-0.057755,0.026243,0.053961,-0.002802,0.007305,0.001190,0.028256,-0.092130,0.054570,0.035101,0.063746,0.000813,0.018161,0.026468,-0.052213,0.003892,-0.026053,0.031672,0.014138,-