  lesson_ar = excluded.lesson_ar, embedding = excluded.embedding;

insert into public.profiles (slug, display_name_en, display_name_ar, age, avatar_emoji, xp)
values ('salma', 'Salma', 'سلمى', 9, '🦋', 320)
on conflict (slug) do update set
  display_name_en = excluded.display_name_en,
  display_name_ar = excluded.display_name_ar,
  age = excluded.age, avatar_emoji = excluded.avatar_emoji, xp = excluded.xp;

insert into public.badges
  (slug, name_en, name_ar, description_en, description_ar, icon, xp_required, sort_order)
values
  ('first-story', 'First Story', 'أول حكاية', 'Log your very first book.', 'سجّل كتابك الأول.', '📖', 50, 1),
  ('story-circle-voice', 'Story Circle Voice', 'صوت حلقة الحكايا', 'Take part in a library story circle.', 'شارك في حلقة حكايا المكتبة.', '🎤', 150, 2),
  ('book-explorer', 'Book Explorer', 'رحّالة الكتب', 'Log five different books.', 'سجّل خمسة كتب مختلفة.', '🧭', 250, 3),
  ('library-hopper', 'Library Hopper', 'جوّالة المكتبات', 'Visit three different partner libraries.', 'زُر ثلاث مكتبات شريكة مختلفة.', '🏛️', 500, 4)
on conflict (slug) do update set
  name_en = excluded.name_en, name_ar = excluded.name_ar,
  description_en = excluded.description_en, description_ar = excluded.description_ar,
  icon = excluded.icon, xp_required = excluded.xp_required,
  sort_order = excluded.sort_order;

insert into public.profile_badges (profile_id, badge_id)
select p.id, b.id
from public.profiles p
join public.badges b on b.slug in ('first-story', 'story-circle-voice', 'book-explorer')
where p.slug = 'salma'
on conflict (profile_id, badge_id) do nothing;

insert into public.reading_logs (profile_id, book_id)
select p.id, bk.id
from public.profiles p
join public.books bk on bk.slug in ('the-olive-trees-secret', 'the-turtle-who-carried-stories', 'the-kite-that-learned-to-read', 'grandmothers-bread', 'the-cat-of-the-old-souq', 'the-paper-boat-race')
where p.slug = 'salma'
on conflict (profile_id, book_id) do nothing;
